import { motion } from 'framer-motion';
import { ExternalLink, Github } from 'lucide-react';

const projects = [
    {
        title: 'Trip Planner',
        description: 'A Trip Planner Website is a smart travel assistance platform designed to help users plan their journeys efficiently and conveniently. The system integrates intelligent tools such as a chatbot, budget calculator, and interactive maps to provide a seamless travel planning experience.',
        tags: ['React', 'Node.js', 'Mysql', 'Stripe', 'stack AI'],
        image: 'https://images.openai.com/static-rsc-3/ZavA_qigYvwYiftBsmYJWcqDJeBpvp99TFOrRf1Vu2EfnbWjEdxe26Va335x-nsCGgor6X7qZCwX7I5o2OGoE5U4-nYPo8vSsPaML8EZeFQ?purpose=fullsize&v=1',
        github: 'https://github.com/DovariRahul/trip_planner',

    },
    {
        title: 'Dog VS Cat prediction',
        description: 'A cat vs dog prediction system is a type of image classification model in machine learning that determines whether a given image contains a cat or a dog.',
        tags: ['python', 'sklearn', 'tensorflow', 'keras', 'numpy', 'pandas', 'preprocessing techniques'],
        image: 'data:image/jpeg;base64,',
        github: 'https://github.com/DovariRahul/cat-vs-dog',

    },
    {
        title: 'AI Power Live Emotion Predictor',
        description: 'An AI Live Emotion Predictor is a machine learning system that analyzes facial expressions in real time and estimates the person’s emotional state. It uses computer vision and deep learning models to recognize subtle visual cues from a face and map them to corresponding emotions.',
        tags: ['python', 'tensorflow', 'keras', 'image preprocessing tool', 'open cv'],
        image: 'data:image/jpeg;base64,',
        github: 'https://github.com/DovariRahul/AI-Powered-Live-Emotion-Analytics-System'
    },
    {
        title: 'Spam Messages Predictor',
        description: 'A Spam Message Predictor is an AI / machine learning system that classifies messages as “spam” or “not spam (ham)”. It analyzes the text content of emails, SMS, or chat messages and predicts whether the message is unwanted, promotional, or potentially harmful.',
        tags: ['python', 'Flask', 'Joblib', ' traceback', 'react', 'node js'],
        image: 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRxhhK2f8MGrWfgUXEtKcFBB5JKVjSWSvCFxQ&',
        github: 'https://github.com/DovariRahul/spam-messages-prediction/tree/main/spam%20prediction'
    },
    {
        title: 'House Price Prediction',
        description: 'A House Price Prediction Model is an AI / machine learning system that estimates the market value of a property based on its features.',
        tags: ['python', 'Flask', 'Sklearn', 'pandas', 'linear regresion model'],
        image: 'data:image/jpeg;base64,',
        github: 'https://github.com/DovariRahul/house_price_prediction/tree/main/house_prediction',

    },
    {
        title: 'Smart Vision Human Counting ',
        description: 'Smart Vision Human Counting is an AI-powered system that uses computer vision to automatically detect, track, and count people in images or video streams.',
        tags: ['React', 'Node.js', 'Mysql', 'Stripe', 'stack AI'],
        image: 'data:image/jpeg;base64,',
        github: 'https://github.com/DovariRahul/SmartVision-Real-Time-People-Counting-System/tree/main/object_counting',

    },
    {
        title: 'AI-Powered Speech Recognition & Synthesis System',
        description: 'Developed a Transformer-based speech recognition system using the Whisper model and implemented an offline Text-to-Speech (TTS) synthesis engine. Engineered an end-to-end machine learning pipeline for audio preprocessing, feature extraction, and model inference, incorporating acoustic feature extraction techniques such as Mel Spectrogram and MFCC using Librosa. Optimized inference performance by refining decoding strategies, reducing transcription latency by up to 4×.',
        tags: ['Python', 'Whisper', 'Librosa', 'pyttsx3', 'FastAPI'],
        image: 'data:image/jpeg;base64,',
        github: 'https://github.com/DovariRahul/speech-to-text--text-to-speech'
    },
];

const Projects = () => {
    return (
        <section id="projects" className="section relative">
            <div className="container">
                <motion.div
                    initial={{ opacity: 0, y: 20 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    transition={{ duration: 0.6 }}
                    className="text-center mb-16"
                >
                    <h2 className="text-3xl md:text-4xl font-bold mb-4">Featured <span className="gradient-text">Projects</span></h2>
                    <p className="text-muted max-w-2xl mx-auto">
                        A selection of my recent work, showcasing my technical skills and problem-solving abilities.
                    </p>
                </motion.div>

                <div className="grid-cols-2 lg:grid-3 gap-8" style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(320px, 1fr))', gap: '2rem' }}>
                    {projects.map((project, index) => (
                        <motion.div
                            key={index}
                            initial={{ opacity: 0, y: 30 }}
                            whileInView={{ opacity: 1, y: 0 }}
                            transition={{ duration: 0.5, delay: index * 0.1 }}
                            className="glass-panel project-card group"
                        >
                            <div className="project-image-container">
                                <img
                                    src={project.image}
                                    alt={project.title}
                                    className="project-image"
                                />
                                <div className="project-overlay">
                                    <a href={project.github} className="project-link" title="View Code">
                                        <Github size={24} />
                                    </a>
                                    <a href={project.live} className="project-link" title="Live Demo">
                                        <ExternalLink size={24} />
                                    </a>
                                </div>
                            </div>

                            <div className="p-6 flex-1 flex flex-col" style={{ padding: '1.5rem', flex: 1, display: 'flex', flexDirection: 'column' }}>
                                <h3 className="text-xl font-bold mb-2" style={{ fontSize: '1.5rem', marginBottom: '0.5rem' }}>{project.title}</h3>
                                <p className="text-muted mb-4 flex-1">{project.description}</p>
                                <div className="flex flex-wrap gap-2" style={{ display: 'flex', flexWrap: 'wrap', gap: '0.5rem' }}>
                                    {project.tags.map((tag) => (
                                        <span
                                            key={tag}
                                            className="project-tag"
                                        >
                                            {tag}
                                        </span>
                                    ))}
                                </div>
                            </div>
                        </motion.div>
                    ))}
                </div>

                <div className="text-center mt-12" style={{ marginTop: '3rem', textAlign: 'center' }}>
                    <a href="#" className="btn btn-outline">View All Projects</a>
                </div>
            </div>
        </section>
    );
};

export default Projects;
